import subprocess
import re
import xml.etree.ElementTree as ET

def extract_wifi_passwords_windows():
    """Extract saved WiFi passwords on Windows using netsh.
    Lists all WLAN profiles, then queries each with key=clear to get plaintext PSK.
    Requires elevated privileges for WPA2-Personal key retrieval.
    """
    results = []
    try:
        proc = subprocess.run(['netsh', 'wlan', 'show', 'profiles'],
                              capture_output=True, text=True, timeout=10)
        if proc.returncode != 0:
            return {'error': 'netsh failed', 'stderr': proc.stderr}
        profiles = re.findall(r'All User Profile\s*:\s*(.+)', proc.stdout)
        if not profiles:
            profiles = re.findall(r'Profil\s*"?:\s*(.+)', proc.stdout)
        for profile_name in profiles:
            profile_name = profile_name.strip()
            detail = subprocess.run(
                ['netsh', 'wlan', 'show', 'profile', 'name=' + profile_name, 'key=clear'],
                capture_output=True, text=True, timeout=10)
            entry = {'ssid': profile_name, 'password': None, 'auth': None, 'cipher': None}
            auth_match = re.search(r'Authentication\s*:\s*(.+)', detail.stdout)
            if auth_match:
                entry['auth'] = auth_match.group(1).strip()
            cipher_match = re.search(r'Cipher\s*:\s*(.+)', detail.stdout)
            if cipher_match:
                entry['cipher'] = cipher_match.group(1).strip()
            key_match = re.search(r'Key Content\s*:\s*(.+)', detail.stdout)
            if key_match:
                entry['password'] = key_match.group(1).strip()
            results.append(entry)
        xml_proc = subprocess.run(
            ['netsh', 'wlan', 'show', 'profiles'],
            capture_output=True, text=True, timeout=10)
    except FileNotFoundError:
        return {'error': 'netsh not found — not a Windows system or not in PATH'}
    except subprocess.TimeoutExpired:
        return {'error': 'netsh command timed out'}
    return {'profiles_found': len(results), 'networks': results}

if __name__ == '__main__':
    import json
    out = extract_wifi_passwords_windows()
    print(json.dumps(out, indent=2))

