import os
import glob
import configparser

def extract_wifi_passwords_linux():
    """Extract WiFi passwords from NetworkManager connection files.
    NM stores configs in /etc/NetworkManager/system-connections/*.nmconnection
    (or without .nmconnection extension on older systems).
    Files are INI-like with [wifi] ssid= and [wifi-security] psk= fields.
    Requires root to read these files (mode 0600 owned by root).
    """
    nm_dirs = ['/etc/NetworkManager/system-connections']
    patterns = ['*.nmconnection', '*']
    results = []
    for nm_dir in nm_dirs:
        if not os.path.isdir(nm_dir):
            continue
        conn_files = []
        for pattern in patterns:
            conn_files.extend(glob.glob(os.path.join(nm_dir, pattern)))
        conn_files = list(set(f for f in conn_files if os.path.isfile(f)))
        for conn_file in sorted(conn_files):
            entry = {'file': conn_file, 'ssid': None, 'psk': None,
                     'key_mgmt': None, 'readable': False}
            try:
                parser = configparser.ConfigParser(interpolation=None)
                parser.read(conn_file)
                entry['readable'] = True
                if parser.has_section('wifi'):
                    entry['ssid'] = parser.get('wifi', 'ssid', fallback=None)
                    entry['mode'] = parser.get('wifi', 'mode', fallback='infrastructure')
                if parser.has_section('wifi-security'):
                    entry['key_mgmt'] = parser.get('wifi-security', 'key-mgmt', fallback=None)
                    entry['psk'] = parser.get('wifi-security', 'psk', fallback=None)
                    entry['auth_alg'] = parser.get('wifi-security', 'auth-alg', fallback=None)
                if parser.has_section('802-1x'):
                    entry['eap_identity'] = parser.get('802-1x', 'identity', fallback=None)
                    entry['eap_password'] = parser.get('802-1x', 'password', fallback=None)
                if parser.has_section('connection'):
                    entry['conn_type'] = parser.get('connection', 'type', fallback=None)
                    entry['conn_id'] = parser.get('connection', 'id', fallback=None)
            except PermissionError:
                entry['error'] = 'permission denied (need root)'
            except configparser.Error as e:
                entry['error'] = str(e)
            if entry.get('ssid') or entry.get('error'):
                results.append(entry)
    wpa_supplicant = '/etc/wpa_supplicant/wpa_supplicant.conf'
    if os.path.isfile(wpa_supplicant):
        try:
            with open(wpa_supplicant, 'r') as f:
                content = f.read()
            import re
            for block in re.finditer(r'network=\{([^}]+)\}', content):
                body = block.group(1)
                ssid_m = re.search(r'ssid="([^"]+)"', body)
                psk_m = re.search(r'psk="([^"]+)"', body)
                if ssid_m:
                    results.append({'file': wpa_supplicant, 'ssid': ssid_m.group(1),
                                    'psk': psk_m.group(1) if psk_m else None, 'source': 'wpa_supplicant'})
        except PermissionError:
            results.append({'file': wpa_supplicant, 'error': 'permission denied'})
    return {'networks_found': len(results), 'networks': results}

if __name__ == '__main__':
    import json
    out = extract_wifi_passwords_linux()
    print(json.dumps(out, indent=2))

