import os
import glob
import re
import stat

def discover_ssh_keys(scan_users=True):
    """Discover SSH private keys, check encryption status, list authorized_keys targets.
    Scans ~/.ssh/ for id_rsa, id_ed25519, id_ecdsa, id_dsa and custom key files.
    Checks BEGIN ENCRYPTED vs BEGIN RSA/OPENSSH to determine if passphrase-protected.
    Parses authorized_keys and known_hosts for lateral movement targets.
    """
    home = os.path.expanduser('~')
    ssh_dirs = [os.path.join(home, '.ssh')]
    if scan_users and os.path.isdir('/home'):
        for user in os.listdir('/home'):
            user_ssh = os.path.join('/home', user, '.ssh')
            if os.path.isdir(user_ssh):
                ssh_dirs.append(user_ssh)
    if scan_users and os.path.isdir('/root/.ssh'):
        ssh_dirs.append('/root/.ssh')
    key_patterns = ['id_rsa', 'id_ed25519', 'id_ecdsa', 'id_dsa', 'id_xmss', '*.pem', '*.key']
    results = {'keys': [], 'authorized_keys': [], 'known_hosts': [], 'config_hosts': []}
    for ssh_dir in ssh_dirs:
        if not os.path.isdir(ssh_dir):
            continue
        for pattern in key_patterns:
            for key_path in glob.glob(os.path.join(ssh_dir, pattern)):
                if key_path.endswith('.pub'):
                    continue
                key_info = {'path': key_path, 'encrypted': None, 'type': None, 'permissions': None}
                try:
                    st = os.stat(key_path)
                    key_info['permissions'] = oct(st.st_mode & 0o777)
                    key_info['size'] = st.st_size
                    with open(key_path, 'r') as f:
                        header = f.read(512)
                    if 'BEGIN ENCRYPTED PRIVATE KEY' in header or 'ENCRYPTED' in header:
                        key_info['encrypted'] = True
                    elif 'BEGIN' in header and 'PRIVATE KEY' in header:
                        key_info['encrypted'] = False
                        if 'BEGIN OPENSSH PRIVATE KEY' in header:
                            aes_check = 'aes' in header.lower() or 'bcrypt' in header[:200].lower()
                            key_info['encrypted'] = aes_check
                    if 'RSA' in header:
                        key_info['type'] = 'RSA'
                    elif 'EC' in header:
                        key_info['type'] = 'ECDSA'
                    elif 'OPENSSH' in header:
                        key_info['type'] = 'OpenSSH'
                    elif 'DSA' in header:
                        key_info['type'] = 'DSA'
                except PermissionError:
                    key_info['error'] = 'permission denied'
                results['keys'].append(key_info)
        auth_keys_path = os.path.join(ssh_dir, 'authorized_keys')
        if os.path.isfile(auth_keys_path):
            try:
                with open(auth_keys_path, 'r') as f:
                    for line in f:
                        line = line.strip()
                        if line and not line.startswith('#'):
                            parts = line.split()
                            comment = parts[-1] if len(parts) >= 3 else ''
                            results['authorized_keys'].append(
                                {'file': auth_keys_path, 'key_type': parts[0] if parts else '',
                                 'comment': comment})
            except PermissionError:
                pass
        known_hosts_path = os.path.join(ssh_dir, 'known_hosts')
        if os.path.isfile(known_hosts_path):
            try:
                with open(known_hosts_path, 'r') as f:
                    for line in f:
                        line = line.strip()
                        if line and not line.startswith('#'):
                            host = line.split()[0] if line.split() else ''
                            results['known_hosts'].append(host)
            except PermissionError:
                pass
        config_path = os.path.join(ssh_dir, 'config')
        if os.path.isfile(config_path):
            try:
                with open(config_path, 'r') as f:
                    current_host = None
                    for line in f:
                        line = line.strip()
                        if line.lower().startswith('host '):
                            current_host = {'alias': line.split(None, 1)[1]}
                            results['config_hosts'].append(current_host)
                        elif current_host and line.lower().startswith('hostname'):
                            current_host['hostname'] = line.split(None, 1)[1]
                        elif current_host and line.lower().startswith('user'):
                            current_host['user'] = line.split(None, 1)[1]
                        elif current_host and line.lower().startswith('identityfile'):
                            current_host['identity_file'] = line.split(None, 1)[1]
            except PermissionError:
                pass
    unencrypted = [k for k in results['keys'] if k.get('encrypted') is False]
    results['summary'] = {'total_keys': len(results['keys']),
                           'unencrypted_keys': len(unencrypted),
                           'lateral_targets': len(set(results['known_hosts'])),
                           'ssh_config_hosts': len(results['config_hosts'])}
    return results

if __name__ == '__main__':
    import json
    out = discover_ssh_keys()
    print(json.dumps(out, indent=2))

