import subprocess
import re
import platform

def extract_windows_credentials():
    """Extract stored credentials from Windows Credential Manager.
    Uses cmdkey /list to enumerate cached credentials (generic, domain, certificate).
    Uses vaultcmd /list to enumerate credential vaults.
    Requires the current user session; no elevation needed for own credentials.
    On non-Windows: returns diagnostic info only.
    """
    if platform.system() != 'Windows':
        return {'error': 'Windows-only tool', 'system': platform.system()}
    results = {'cmdkey_credentials': [], 'vaults': [], 'dpapi_blobs': []}
    try:
        proc = subprocess.run(['cmdkey', '/list'], capture_output=True, text=True, timeout=10)
        if proc.returncode == 0:
            current = None
            for line in proc.stdout.splitlines():
                line = line.strip()
                if line.startswith('Target:'):
                    if current:
                        results['cmdkey_credentials'].append(current)
                    target = line.split(':', 1)[1].strip()
                    target = re.sub(r'^\s*\S+\s*=\s*', '', target)
                    current = {'target': target, 'type': None, 'user': None}
                elif line.startswith('Type:') and current:
                    current['type'] = line.split(':', 1)[1].strip()
                elif line.startswith('User:') and current:
                    current['user'] = line.split(':', 1)[1].strip()
                elif line.startswith('Local machine persistence') and current:
                    current['persistence'] = line.split(':', 1)[1].strip()
            if current:
                results['cmdkey_credentials'].append(current)
    except (FileNotFoundError, subprocess.TimeoutExpired) as e:
        results['cmdkey_error'] = str(e)
    try:
        proc = subprocess.run(['vaultcmd', '/list'], capture_output=True, text=True, timeout=10)
        if proc.returncode == 0:
            for line in proc.stdout.splitlines():
                line = line.strip()
                if 'Vault:' in line or 'GUID' in line:
                    results['vaults'].append(line)
    except (FileNotFoundError, subprocess.TimeoutExpired) as e:
        results['vaultcmd_error'] = str(e)
    import os
    appdata = os.environ.get('APPDATA', '')
    dpapi_dir = os.path.join(appdata, 'Microsoft', 'Credentials')
    if os.path.isdir(dpapi_dir):
        for entry in os.listdir(dpapi_dir):
            full_path = os.path.join(dpapi_dir, entry)
            if os.path.isfile(full_path):
                results['dpapi_blobs'].append(
                    {'path': full_path, 'size': os.path.getsize(full_path)})
    results['summary'] = {'cmdkey_count': len(results['cmdkey_credentials']),
                           'vault_count': len(results['vaults']),
                           'dpapi_blob_count': len(results['dpapi_blobs'])}
    return results

if __name__ == '__main__':
    import json
    out = extract_windows_credentials()
    print(json.dumps(out, indent=2))

