import os
import sqlite3
import shutil
import tempfile
import platform
import glob
import time

def extract_browser_cookies(target_domains=None):
    """Extract cookies from Chrome and Firefox cookie stores.
    Chrome: ~/.../<Profile>/Cookies SQLite DB (host_key, name, encrypted_value, expires_utc).
    Firefox: ~/.../<Profile>/cookies.sqlite (host, name, value, expiry).
    Copies DBs to temp before reading (locked by running browsers).
    """
    home = os.path.expanduser('~')
    sys_name = platform.system()
    results = {'chrome': [], 'firefox': []}
    chrome_cookie_dbs = []
    if sys_name == 'Linux':
        for bd in ['google-chrome', 'chromium']:
            base = os.path.join(home, '.config', bd)
            if os.path.isdir(base):
                for entry in os.listdir(base):
                    db = os.path.join(base, entry, 'Cookies')
                    if os.path.isfile(db):
                        chrome_cookie_dbs.append(db)
    elif sys_name == 'Darwin':
        base = os.path.join(home, 'Library', 'Application Support', 'Google', 'Chrome')
        if os.path.isdir(base):
            for entry in os.listdir(base):
                db = os.path.join(base, entry, 'Cookies')
                if os.path.isfile(db):
                    chrome_cookie_dbs.append(db)
    elif sys_name == 'Windows':
        appdata = os.environ.get('LOCALAPPDATA', '')
        base = os.path.join(appdata, 'Google', 'Chrome', 'User Data')
        if os.path.isdir(base):
            for entry in os.listdir(base):
                for name in ['Cookies', 'Network/Cookies']:
                    db = os.path.join(base, entry, name)
                    if os.path.isfile(db):
                        chrome_cookie_dbs.append(db)
    for db_path in chrome_cookie_dbs:
        tmp_fd, tmp_path = tempfile.mkstemp(suffix='.db')
        os.close(tmp_fd)
        try:
            shutil.copy2(db_path, tmp_path)
            conn = sqlite3.connect(tmp_path)
            cursor = conn.cursor()
            query = 'SELECT host_key, name, encrypted_value, expires_utc, is_secure, is_httponly, path FROM cookies'
            if target_domains:
                placeholders = ','.join('?' for _ in target_domains)
                query += ' WHERE ' + ' OR '.join('host_key LIKE ?' for _ in target_domains)
                cursor.execute(query, ['%' + d + '%' for d in target_domains])
            else:
                cursor.execute(query)
            for host, name, enc_val, expires, secure, httponly, path in cursor.fetchall():
                results['chrome'].append({'source': db_path, 'host': host, 'name': name,
                    'encrypted_value_len': len(enc_val) if enc_val else 0,
                    'expires_utc': expires, 'secure': bool(secure),
                    'httponly': bool(httponly), 'path': path})
            conn.close()
        except sqlite3.OperationalError as e:
            results['chrome'].append({'source': db_path, 'error': str(e)})
        finally:
            os.unlink(tmp_path)
    ff_cookie_dbs = []
    if sys_name == 'Linux':
        ff_cookie_dbs = glob.glob(os.path.join(home, '.mozilla', 'firefox', '*', 'cookies.sqlite'))
    elif sys_name == 'Darwin':
        ff_cookie_dbs = glob.glob(os.path.join(home, 'Library', 'Application Support',
                                                'Firefox', 'Profiles', '*', 'cookies.sqlite'))
    elif sys_name == 'Windows':
        appdata = os.environ.get('APPDATA', '')
        ff_cookie_dbs = glob.glob(os.path.join(appdata, 'Mozilla', 'Firefox', 'Profiles', '*', 'cookies.sqlite'))
    for db_path in ff_cookie_dbs:
        tmp_fd, tmp_path = tempfile.mkstemp(suffix='.db')
        os.close(tmp_fd)
        try:
            shutil.copy2(db_path, tmp_path)
            conn = sqlite3.connect(tmp_path)
            cursor = conn.cursor()
            query = 'SELECT host, name, value, expiry, isSecure, isHttpOnly, path FROM moz_cookies'
            if target_domains:
                query += ' WHERE ' + ' OR '.join('host LIKE ?' for _ in target_domains)
                cursor.execute(query, ['%' + d + '%' for d in target_domains])
            else:
                cursor.execute(query)
            for host, name, value, expiry, secure, httponly, path in cursor.fetchall():
                results['firefox'].append({'source': db_path, 'host': host, 'name': name,
                    'value_len': len(value) if value else 0, 'has_value': bool(value),
                    'expiry': expiry, 'secure': bool(secure),
                    'httponly': bool(httponly), 'path': path})
            conn.close()
        except sqlite3.OperationalError as e:
            results['firefox'].append({'source': db_path, 'error': str(e)})
        finally:
            os.unlink(tmp_path)
    results['summary'] = {'chrome_cookies': len(results['chrome']),
                           'firefox_cookies': len(results['firefox'])}
    return results

if __name__ == '__main__':
    import json
    out = extract_browser_cookies()
    print(json.dumps(out, indent=2))

