import os
import re
import glob

def extract_env_secrets(scan_root=None, max_depth=4):
    """Extract secrets from .env files, config files, and settings files.
    Recursively scans for .env, .env.local, config.yml, settings.py, etc.
    Parses KEY=VALUE pairs and flags entries containing password, secret,
    token, api_key, private_key, database_url, and similar patterns.
    """
    if scan_root is None:
        scan_root = os.path.expanduser('~')
    SECRET_PATTERNS = re.compile(
        r'(password|passwd|secret|token|api[_-]?key|private[_-]?key|'
        r'access[_-]?key|auth[_-]?token|database[_-]?url|connection[_-]?string|'
        r'smtp[_-]?pass|aws[_-]?secret|client[_-]?secret|encryption[_-]?key)',
        re.IGNORECASE)
    TARGET_FILES = ['.env', '.env.local', '.env.production', '.env.staging',
                    '.env.development', '.env.test', '.flaskenv',
                    'config.yml', 'config.yaml', 'config.json', 'config.ini',
                    'settings.py', 'settings.ini', 'settings.cfg',
                    'credentials', 'credentials.json', 'secrets.yml',
                    'database.yml', 'application.properties', 'wp-config.php',
                    '.npmrc', '.pypirc', '.netrc', '.pgpass', '.my.cnf']
    KV_PATTERN = re.compile(r'^\s*([A-Za-z_][A-Za-z0-9_]*)\s*[=:]\s*["\']?(.+?)["\']?\s*$')
    results = []
    files_scanned = 0
    for dirpath, dirnames, filenames in os.walk(scan_root):
        depth = dirpath[len(scan_root):].count(os.sep)
        if depth >= max_depth:
            dirnames.clear()
            continue
        skip_dirs = {'.git', 'node_modules', '__pycache__', '.venv', 'venv', '.tox', 'vendor'}
        dirnames[:] = [d for d in dirnames if d not in skip_dirs]
        for fname in filenames:
            if fname not in TARGET_FILES:
                continue
            fpath = os.path.join(dirpath, fname)
            files_scanned += 1
            try:
                with open(fpath, 'r', errors='ignore') as f:
                    for line_num, line in enumerate(f, 1):
                        if line.strip().startswith('#') or not line.strip():
                            continue
                        match = KV_PATTERN.match(line)
                        if match:
                            key, value = match.group(1), match.group(2)
                            if SECRET_PATTERNS.search(key):
                                masked = value[:3] + '*' * max(0, len(value) - 6) + value[-3:] if len(value) > 8 else '***'
                                results.append({'file': fpath, 'line': line_num,
                                                'key': key, 'value_masked': masked,
                                                'value_length': len(value)})
            except (PermissionError, IOError):
                pass
    dot_env_globs = glob.glob(os.path.join(scan_root, '**', '.env*'), recursive=True)
    for env_file in dot_env_globs:
        if not os.path.isfile(env_file):
            continue
        if any(r['file'] == env_file for r in results):
            continue
        try:
            with open(env_file, 'r', errors='ignore') as f:
                for line_num, line in enumerate(f, 1):
                    if line.strip().startswith('#') or not line.strip():
                        continue
                    match = KV_PATTERN.match(line)
                    if match:
                        key, value = match.group(1), match.group(2)
                        if SECRET_PATTERNS.search(key):
                            masked = value[:3] + '*' * max(0, len(value) - 6) + value[-3:] if len(value) > 8 else '***'
                            results.append({'file': env_file, 'line': line_num,
                                            'key': key, 'value_masked': masked,
                                            'value_length': len(value)})
        except (PermissionError, IOError):
            pass
    return {'scan_root': scan_root, 'files_scanned': files_scanned,
            'secrets_found': len(results), 'secrets': results}

