import os
import re
import glob
import json
from urllib.parse import urlparse, unquote

def extract_git_credentials(scan_repos=True):
    """Extract credentials from git config and credential stores.
    Reads ~/.git-credentials (plaintext URLs with embedded passwords),
    ~/.gitconfig for credential.helper settings,
    scans .git/config files in repos for embedded tokens in remote URLs.
    """
    home = os.path.expanduser('~')
    results = {'plaintext_credentials': [], 'credential_helpers': [],
               'repo_tokens': [], 'git_configs': []}
    git_cred_paths = [os.path.join(home, '.git-credentials'),
                      os.path.join(home, '.config', 'git', 'credentials')]
    for cred_path in git_cred_paths:
        if not os.path.isfile(cred_path):
            continue
        try:
            with open(cred_path, 'r') as f:
                for line_num, line in enumerate(f, 1):
                    line = line.strip()
                    if not line or line.startswith('#'):
                        continue
                    try:
                        parsed = urlparse(line)
                        if parsed.password:
                            results['plaintext_credentials'].append({
                                'file': cred_path, 'line': line_num,
                                'host': parsed.hostname, 'username': unquote(parsed.username or ''),
                                'password_length': len(parsed.password),
                                'protocol': parsed.scheme})
                    except Exception:
                        pass
        except PermissionError:
            pass
    gitconfig_paths = [os.path.join(home, '.gitconfig'),
                       os.path.join(home, '.config', 'git', 'config'),
                       '/etc/gitconfig']
    for config_path in gitconfig_paths:
        if not os.path.isfile(config_path):
            continue
        try:
            with open(config_path, 'r') as f:
                content = f.read()
            helper_matches = re.findall(r'helper\s*=\s*(.+)', content)
            for helper in helper_matches:
                helper = helper.strip()
                results['credential_helpers'].append(
                    {'file': config_path, 'helper': helper,
                     'is_store': 'store' in helper,
                     'is_cache': 'cache' in helper,
                     'is_osxkeychain': 'osxkeychain' in helper})
            user_match = re.search(r'\[user\][^\[]*?name\s*=\s*(.+)', content, re.DOTALL)
            email_match = re.search(r'\[user\][^\[]*?email\s*=\s*(.+)', content, re.DOTALL)
            if user_match or email_match:
                results['git_configs'].append({
                    'file': config_path,
                    'user': user_match.group(1).strip() if user_match else None,
                    'email': email_match.group(1).strip() if email_match else None})
        except PermissionError:
            pass
    if scan_repos:
        TOKEN_PATTERN = re.compile(
            r'(ghp_[A-Za-z0-9]{36}|gho_[A-Za-z0-9]{36}|github_pat_[A-Za-z0-9_]{82}|'
            r'glpat-[A-Za-z0-9\-]{20}|xoxb-[A-Za-z0-9\-]+|xoxp-[A-Za-z0-9\-]+)')
        repo_search_dirs = [home, os.path.join(home, 'Documents'),
                            os.path.join(home, 'projects'), os.path.join(home, 'repos'),
                            os.path.join(home, 'src'), os.path.join(home, 'Desktop')]
        seen_repos = set()
        for search_dir in repo_search_dirs:
            if not os.path.isdir(search_dir):
                continue
            for dirpath, dirnames, filenames in os.walk(search_dir):
                depth = dirpath[len(search_dir):].count(os.sep)
                if depth >= 3:
                    dirnames.clear()
                    continue
                dirnames[:] = [d for d in dirnames if d not in {'node_modules', '.venv', 'venv', '__pycache__'}]
                if '.git' in dirnames or '.git' in filenames:
                    git_config = os.path.join(dirpath, '.git', 'config')
                    if git_config in seen_repos or not os.path.isfile(git_config):
                        continue
                    seen_repos.add(git_config)
                    try:
                        with open(git_config, 'r') as f:
                            content = f.read()
                        urls = re.findall(r'url\s*=\s*(.+)', content)
                        for url in urls:
                            url = url.strip()
                            token_match = TOKEN_PATTERN.search(url)
                            if token_match:
                                results['repo_tokens'].append({
                                    'repo': dirpath, 'token_type': token_match.group(0)[:4] + '...',
                                    'token_length': len(token_match.group(0))})
                            try:
                                parsed = urlparse(url)
                                if parsed.password or (parsed.username and parsed.username not in ['git', 'oauth2']):
                                    results['repo_tokens'].append({
                                        'repo': dirpath, 'host': parsed.hostname,
                                        'username': parsed.username,
                                        'has_password': bool(parsed.password)})
                            except Exception:
                                pass
                    except PermissionError:
                        pass
    results['summary'] = {
        'plaintext_creds': len(results['plaintext_credentials']),
        'credential_helpers': len(results['credential_helpers']),
        'repo_embedded_tokens': len(results['repo_tokens'])}
    return results

if __name__ == '__main__':
    out = extract_git_credentials()
    print(json.dumps(out, indent=2))
